#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char strs[101][101];
        for(int i=0;i<N;++i) scanf("%100s",strs[i]);
        int pref=0;
        for(int i=0; strs[0][i]!='\0'; ++i){
            char c=strs[0][i];
            int ok=1;
            for(int j=1;j<N;++j){
                if(strs[j][i]=='\0' || strs[j][i]!=c){ ok=0; break; }
            }
            if(!ok) break;
            ++pref;
        }
        if(pref==0) printf("-1\n");
        else{ strs[0][pref]='\0'; printf("%s\n",strs[0]); }
    }
    return 0;
}

