import sys
def solve():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        N=int(next(it))
        strs=[next(it) for _ in range(N)]
        pref=0
        for i,ch in enumerate(strs[0]):
            if all(i<len(s) and s[i]==ch for s in strs[1:]):
                pref+=1
            else:
                break
        if pref==0:
            out.append('-1')
        else:
            out.append(strs[0][:pref])
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    solve()

